    var list = document.getElementById('context-list');
    var emptyState = document.getElementById('contexts-empty-state');
    if (list && list.children.length === 0 && emptyState) {
        list.hidden = true;
        emptyState.hidden = false;
    }
});
</script>
{% endblock %}

